"use strict";(self.webpackChunkdsd_project=self.webpackChunkdsd_project||[]).push([[5894],{6042:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"Data-Scientist-se-lam-gi-khi-bi-ap-deadline","metadata":{"permalink":"/blog/Data-Scientist-se-lam-gi-khi-bi-ap-deadline","source":"@site/blog/2024/03/14/2024-03-14-data-scientist-voi-deadline.md","title":"Data Scientist se\u0303 la\u0300m gi\u0300 khi bi\u0323 a\u0301p deadline","description":"Data Scientist se\u0303 la\u0300m gi\u0300 khi bi\u0323 a\u0301p deadline","date":"2024-03-14T00:00:00.000Z","formattedDate":"14 th\xe1ng 3, 2024","tags":[{"label":"datasciene","permalink":"/blog/tags/datasciene"},{"label":"deadline","permalink":"/blog/tags/deadline"},{"label":"howto","permalink":"/blog/tags/howto"}],"readingTime":8.665,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Data Scientist se\u0303 la\u0300m gi\u0300 khi bi\u0323 a\u0301p deadline","description":"Data Scientist se\u0303 la\u0300m gi\u0300 khi bi\u0323 a\u0301p deadline","slug":"Data-Scientist-se-lam-gi-khi-bi-ap-deadline","authors":"lhduc","tags":["datasciene","deadline","howto"],"image":"https://i.pinimg.com/564x/3b/29/50/3b2950afe79ddc47c21125285f3ff1f6.jpg","hide_table_of_contents":false},"unlisted":false,"nextItem":{"title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","permalink":"/blog/10-loi-sai-visualization"}},"content":"![](https://i.pinimg.com/564x/3b/29/50/3b2950afe79ddc47c21125285f3ff1f6.jpg)\\r\\n\\r\\n*D\u01b0\u0323 a\u0301n Data Science cu\u0303ng t\u01b0\u01a1ng t\u01b0\u0323 ca\u0301c d\u01b0\u0323 a\u0301n kha\u0301c, lu\xf4n co\u0301 gi\u01a1\u0301i ha\u0323n th\u01a1\u0300i gian hoa\u0300n tha\u0300nh (deadline), va\u0300 th\xf4ng th\u01b0\u01a1\u0300ng m\xf4\u0323t d\u01b0\u0323 a\u0301n th\u01b0\u01a1\u0300ng co\u0301 th\u01a1\u0300i gian khoa\u0309ng 6 tha\u0301ng. Tuy nhi\xean \u0111\xf4i khi chu\u0301ng ta bi\u0323 e\u0301p deadline xu\xf4\u0301ng co\u0300n 3 tha\u0301ng (1 Quy\u0301) ch\u0103\u0309ng ha\u0323n. V\xe2\u0323y chu\u0301ng ta se\u0303 la\u0300m gi\u0300 \u0111\xea\u0309 tra\u0301nh vi\xea\u0323c hoa\u0309ng loa\u0323n khi bi\u0301 e\u0301p deadline nh\u01b0 th\xea\u0301, la\u0300m sao \u0111\xea\u0309 t\xf4\u0301i \u01b0u th\u01a1\u0300i gian nh\xe2\u0301t co\u0301 th\xea\u0309. Ba\u0300i vi\xea\u0301t d\u01b0\u01a1\u0301i \u0111\xe2y cu\u0309a mi\u0300nh se\u0303 \u0111\u01b0a ra m\xf4\u0323t s\xf4\u0301 kinh nghi\xea\u0323m khi bi\u0323 a\u0301p deadline.*\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n<div class=\\"dot\\">. . .</div>\\r\\n\\r\\n\\r\\n##  L\xean k\xea\u0301 hoa\u0323ch tr\u01b0\u01a1\u0301c \\r\\n\\r\\nVi\xea\u0323c \u0111\xe2\u0300u ti\xean \u0111\xea\u0309 tra\u0301nh vi\xea\u0323c hoa\u0309ng loa\u0323n khi bi\u0323 di\u0301 deadline la\u0300 l\xean k\xea\u0301 hoa\u0323ch tr\u01b0\u01a1\u0301c. Tr\u01b0\u01a1\u0301c khi ba\u0323n b\u0103\u0301t \u0111\xe2\u0300u m\xf4\u0323t d\u01b0\u0323 a\u0301n Khoa ho\u0323c D\u01b0\u0303 li\xea\u0323u, hay \u0111a\u0309m ba\u0309o r\u0103\u0300ng ba\u0323n hi\xea\u0309u \u0111\u01b0\u01a1\u0323c scope cu\u0309a d\u01b0\u0323 a\u0301n, mu\u0323c ti\xeau cu\u0309a d\u01b0\u0323 a\u0301n va\u0300 ky\u0300 vo\u0323ng cu\u0309a kha\u0301ch ha\u0300ng ho\u0103\u0323c ca\u0301c b\xean li\xean quan \u0111\xf4\u0301i v\u01a1\u0301i d\u01b0\u0323 a\u0301n cu\u0309a ba\u0323n nh\u01b0 th\xea\u0301 na\u0300o.\\r\\n\\r\\nSau \u0111o\u0301, ba\u0323n c\xe2\u0300n chia d\u01b0\u0323 a\u0301n cu\u0309a ba\u0323n tha\u0300nh ca\u0301c b\u01b0\u01a1\u0301c nho\u0309 h\u01a1n co\u0301 th\xea\u0309 qua\u0309n ly\u0301 \u0111\u01b0\u01a1\u0323c, d\u01b0\u01a1\u0301i \u0111\xe2y la\u0300 m\xf4\u0323t s\xf4\u0301 b\u01b0\u01a1\u0301c\\r\\n\\r\\n- Thu th\xe2\u0323p d\u01b0\u0303 li\xea\u0323u\\r\\n- La\u0300m sa\u0323ch d\u01b0\u0303 li\xea\u0323u\\r\\n- Khai pha\u0301 d\u01b0\u0303 li\xea\u0323u\\r\\n- Ph\xe2n ti\u0301ch d\u01b0\u0303 li\xea\u0323u\\r\\n- M\xf4 hi\u0300nh ho\u0301a d\u01b0\u0303 li\xea\u0323u\\r\\n- \u0110a\u0301nh gia\u0301 m\xf4 hi\u0300nh\\r\\n- Tri\u0300nh ba\u0300y k\xea\u0301t qua\u0309\\r\\n\\r\\nSau \u0111o\u0301 \u01b0\u01a1\u0301c l\u01b0\u01a1\u0323ng th\u01a1\u0300i gian \u0111\xf4\u0301i v\u01a1\u0301i t\u01b0\u0300ng b\u01b0\u01a1\u0301c va\u0300 ph\xe2n b\xf4\u0309 ngu\xf4\u0300n l\u01b0\u0323c phu\u0300 h\u01a1\u0323p, ba\u0323n co\u0301 th\xea\u0309 s\u01b0\u0309 du\u0323ng ca\u0301c tool qua\u0309n ly\u0301 ho\u0103\u0323c \u0111\u01a1n gia\u0309n la\u0300 l\xean li\u0323ch cho no\u0301 trong google calendar \u0111\xea\u0309 qua\u0309n ly\u0301 va\u0300 thay \u0111\xf4\u0309i khi c\xe2\u0300n thi\xea\u0301t\\r\\n\\r\\nCo\u0301 th\xea\u0309 s\u01b0\u0309 du\u0323ng [MoSCoW prioritisation method](https://en.wikipedia.org/wiki/MoSCoW_method) \u0111\xea\u0309 l\xean y\u0301 t\u01b0\u01a1\u0309ng\\r\\n\\r\\n## T\xe2\u0323p trung va\u0300o nh\u01b0\u0303ng gi\u0300 c\xe2\u0300n thi\xea\u0301t\\r\\n\\r\\nKhi ba\u0323n bi\u0323 di\u0301 deadline, ba\u0323n kh\xf4ng co\u0301 \u0111u\u0309 th\u01a1\u0300i gian \u0111\xea\u0309 \u0111i kha\u0301m pha\u0301 t\u01b0\u0300ng ngo\u0301c nga\u0301ch cu\u0309a d\u01b0\u0303 li\xea\u0323u, do \u0111o\u0301 c\xe2\u0300n co\u0301 chi\xea\u0301n l\u01b0\u01a1\u0323c kha\u0301m pha\u0301 d\u01b0\u0303 li\xea\u0323u phu\u0300 h\u01a1\u0323p. Thay vi\u0300 kha\u0301m pha\u0301 t\xe2\u0301t ca\u0309 ca\u0301c bi\xea\u0301n d\u01b0\u0303 li\xea\u0323u, chu\u0301ng ta n\xean \u0111\u01b0a ra m\xf4\u0323t s\xf4\u0301 c\xe2u ho\u0309i quan tro\u0323ng, sau \u0111o\u0301 li\xea\u0323t k\xea ca\u0301c loa\u0323i d\u01b0\u0303 li\xea\u0323u co\u0301 th\xea\u0309 phu\u0323c vu\u0323 cho vi\xea\u0323c ph\xe2n ti\u0301ch va\u0300 tra\u0309 l\u01a1\u0300i cho c\xe2u ho\u0309i \u0111o\u0301.\\r\\n\\r\\nKh\xe1c v\u1edbi c\xe1c d\u1ef1 \xe1n v\u1edbi d\u1eef li\u1ec7u s\u1eb5n c\xf3 tr\xean m\u1ea1ng, vi\u1ec7c d\u1eef li\u1ec7u b\u1ecb khuy\u1ebft thi\u1ebfu h\u1ea7u h\u1ebft \u0111\u01b0\u1ee3c x\u1eed l\xfd b\u1eb1ng c\xe1c ph\u01b0\u01a1ng ph\xe1p t\xednh trung b\xecnh, t\xednh trung v\u1ecb\\r\\nho\u1eb7c \u0111\u01b0\u1ee3c thay th\u1ebf b\u1eb1ng c\xe1c gi\xe1 tr\u1ecb c\u1ed1 \u0111\u1ecbnh nh\u01b0 0 ho\u1eb7c -999. D\u1eef li\u1ec7u b\u1ecb khuy\u1ebft thi\u1ebfu trong c\xe1c d\u1ef1 \xe1n th\u1ef1c t\u1ebf c\xf3 th\u1ec3 \u0111\u01b0\u1ee3c \u0111i\u1ec1n b\u1eb1ng c\xe1ch thu th\u1eadp d\u1eef li\u1ec7u b\xean ngo\xe0i, v\xed d\u1ee5 nh\u01b0 d\u1eef li\u1ec7u v\u1ec1 v\u1ecb tr\xed \u0111\u1ecba l\xfd c\u1ee7a m\u1ed9t c\u1eeda h\xe0ng c\xf3 th\u1ec3 \u0111\u01b0\u1ee3c thu th\u1eadp b\u1eb1ng Google API hay d\u1eef li\u1ec7u v\u1ec1 d\xe2n s\u1ed1 c\xf3 th\u1ec3 \u0111\u01b0\u1ee3c thu th\u1eadp th\xf4ng qua c\xe1c trang th\u1ed1ng k\xea. Ho\u1eb7c c\xf3 th\u1ec3 n\u1eb1m m\u1ed9t trong b\u1ea3ng n\xe0o \u0111\u1ea5y tr\xean DataWarehouse c\u1ee7a c\xf4ng ty m\xe0 ch\xfang ta ch\u01b0a l\u1ea5y \u0111\u01b0\u1ee3c (v\xed d\u1ee5 b\u1ecb r\xe0ng bu\u1ed9c b\u1edfi quy\u1ec1n h\u1ea1n truy c\u1eadp ch\u1eb3ng h\u1ea1n).\\r\\nVi\u1ec7c t\xecm ki\u1ebfm c\xe1c b\u1ea3ng n\xe0y c\xf3 th\u1ec3 t\u1ed1n nhi\u1ec1u th\u1eddi gian, do \u0111\xf3 n\u1ebfu c\u1ed9t d\u1eef li\u1ec7u b\u1ecb khuy\u1ebft thi\u1ebfu kh\xf4ng qu\xe1 c\u1ea7n thi\u1ebft trong vi\u1ec7c hu\u1ea5n luy\u1ec7n m\xf4 h\xecnh, ch\xfang ta c\xf3 th\u1ec3 b\u1ecf qua d\u1eef li\u1ec7u n\xe0y. \\r\\n\\r\\nL\u01b0u \xfd r\u1eb1ng b\u1ea1n v\u1eabn c\xf3 th\u1ec3 \u0111i\u1ec1n b\u1eb1ng ph\u01b0\u01a1ng ph\xe1p trung b\xecnh(trung v\u1ecb) nh\u01b0 c\xe1ch l\xe0m v\u1edbi d\u1ef1 li\u1ec7u tr\xean m\u1ea1ng nh\u01b0ng ch\u1ec9 n\xean \xe1p d\u1ee5ng cho ph\u1ea7n hu\u1ea5n luy\u1ec7n m\xf4 h\xecnh d\u1ef1 \u0111o\xe1n, c\xf2n trong qu\xe1 tr\xecnh ph\xe2n t\xedch d\u1eef li\u1ec7u, ch\xfang ta \u01b0u ti\xean \u0111\u1ed9 ch\xednh x\xe1c c\u1ee7a b\xe1o c\xe1o do \u0111\xf3 kh\xf4ng n\xean thay th\u1ebf c\xe1c d\u1eef li\u1ec7u \u0111\xf3 b\u1eb1ng m\u1ed9t gi\xe1 tr\u1ecb kh\xf4ng ch\xednh x\xe1c. L\xfac n\xe0y, trong l\xfac tr\xecnh b\xe0y, b\u1ea1n c\u1ea7n \u0111\u01b0a ra s\u1ed1 l\u01b0\u1ee3ng c\xe1c \u0111i\u1ec3m d\u1eef li\u1ec7u b\u1ecb thi\u1ebfu, chi\u1ebfm bao nhi\xeau ph\u1ea7n tr\u0103m v\xe0 \u0111\u01b0a ra l\u01b0u \xfd cho ng\u01b0\u1eddi nghe r\u1eb1ng d\u1eef li\u1ec7u ch\u1ec9 th\u1ed1ng k\xea tr\xean c\xe1c quan s\xe1t kh\xf4ng b\u1ecb thi\u1ebfu d\u1eef li\u1ec7u.\\r\\n\\r\\n\u0110\xf4\u0301i v\u01a1\u0301i vi\xea\u0323c x\xe2y d\u01b0\u0323ng m\xf4 hi\u0300nh d\u01b0\u0323 ba\u0301o, thay vi\u0300 s\u01b0\u0309 du\u0323ng ca\u0301c m\xf4 hi\u0300nh ph\u01b0\u0301c ta\u0323p nh\u01b0 DeepLearning, b\u1ea1n n\xean du\u0300ng ca\u0301c m\xf4 hi\u0300nh \u0111\u01a1n gia\u0309n nh\u01b0 **LinearRegression** ho\u0103\u0323c ca\u0301c m\xf4 hi\u0300nh da\u0323ng c\xe2y nh\u01b0 **LightGBM, XGBoost** ho\u0103\u0323c **CatBoost** . Th\u01a1\u0300i gian hu\xe2\u0301n luy\xea\u0323n cu\u0309a ca\u0301c m\xf4 hi\u0300nh na\u0300y t\u01b0\u01a1ng \u0111\xf4\u0301i ng\u0103\u0301n va\u0300 cu\u0303ng kh\xf4ng m\xe2\u0301t qua\u0301 nhi\xea\u0300u th\u01a1\u0300i gian \u0111\xea\u0309 vi\xea\u0301t code, do \u0111o\u0301 ca\u0301c m\xf4 hi\u0300nh na\u0300y thi\u0301ch h\u01a1\u0323p \u0111\xea\u0309 hu\xe2\u0301n luy\xea\u0323n khi ba\u0323n bi\u0323 a\u0301p deadline. \\r\\n\\r\\nNgoa\u0300i ra, chu\u0301ng ta kh\xf4ng nh\xe2\u0301t thi\xea\u0301t pha\u0309i thi\xea\u0301t l\xe2\u0323p t\xf4\u0301i \u01b0u *hyperparameters(si\xeau tham s\xf4\u0301)* b\u0103\u0300ng ca\u0301c thu\xe2\u0323t toa\u0301n ph\u01b0\u0301c ta\u0323p vi\u0300 ca\u0301c thu\xe2\u0323t toa\u0301n na\u0300y c\xe2\u0300n cha\u0323y la\u0323i m\xf4 hi\u0300nh r\xe2\u0301t nhi\xea\u0300u l\xe2\u0300n do \u0111o\u0301 chu\u0301ng se\u0303 la\u0300m la\u0303ng phi\u0301 th\u01a1\u0300i gian cu\u0309a ba\u0323n kha\u0301 nhi\xea\u0300u trong khi \u0111\xf4\u0323 chi\u0301nh xa\u0301c kh\xf4ng t\u0103ng th\xeam bao nhi\xeau. N\xea\u0301u v\xe2\u0303n mu\xf4\u0301n th\u01b0\u0323c hi\xea\u0323n t\xf4\u0301i \u01b0u si\xeau tham s\xf4\u0301, ba\u0323n co\u0301 th\xea\u0309 xem xe\u0301t ca\u0301c ph\u01b0\u01a1ng pha\u0301p \u0111\u01a1n gia\u0309n nh\u01b0 **GridSearchCV** thay vi\u0300 du\u0300ng ca\u0301c th\u01b0 vi\xea\u0323n nh\u01b0 **hyperopt** ho\u0103\u0323c **optuna**\\r\\n\\r\\nM\u1ed9t l\u1ed7i sai m\xe0 ch\xfang ta hay m\u1eafc ph\u1ea3i l\xe0 c\u1ed1 g\u1eafng t\u1ed1i \u01b0u hi\u1ec7u su\u1ea5t c\u1ee7a m\xf4 h\xecnh v\xe0 \\"sa l\u1ea7y\\" v\xe0o c\xf4ng vi\u1ec7c n\xe0y. H\xe3y \u0111\u1eb7t ra m\u1ed9t gi\u1edbi h\u1ea1n th\u1eddi gian cho vi\u1ec7c t\u1ed1i \\r\\n\u01b0u hi\u1ec7u su\u1ea5t c\u1ee7a m\xf4 h\xecnh. V\xed d\u1ee5 khi ch\u1ea1y th\u1eed nghi\u1ec7m c\xe1c m\xf4 h\xecnh trong v\xf2ng m\u1ed9t tu\u1ea7n m\xe0 hi\u1ec7u su\u1ea5t kh\xf4ng t\u0103ng th\xeam 5% th\xec ch\xfang ta n\xean d\u1eebng l\u1ea1i v\xe0 t\u1eadp trung\\r\\nv\xe0o c\xe1c c\xf4ng vi\u1ec7c kh\xe1c nh\u01b0 vi\u1ebft b\u1ea3ng tr\xecnh b\xe0y ho\u1eb7c x\xe2y d\u1ef1ng service cho m\xf4 h\xecnh c\u1ee7a m\xecnh.\\r\\n\\r\\n\u0110\u1ed1i v\u1edbi m\u1ed9t s\u1ed1 d\u1ef1 \xe1n Data science, b\u1ea1n c\u1ea7n ph\u1ea3i cung c\u1ea5p m\u1ed9t API Service cho ng\u01b0\u1eddi d\xf9ng thay v\xec ch\u1ec9 l\xe0 m\u1ed9t k\u1ebft qu\u1ea3 d\u01b0\u1edbi d\u1ea1ng file ho\u1eb7c l\u01b0u xu\u1ed1ng Database, b\u1ea1n n\xean \u01b0u ti\xean x\xe2y d\u1ef1ng serivce ngay khi \u0111\xe3 ch\u1ea1y \u0111\u01b0\u1ee3c m\u1ed9t m\xf4 h\xecnh \u0111\u01a1n gi\u1ea3n. Sau khi service \u0111\xe3 \u0111\u01b0\u1ee3c thi\u1ebft l\u1eadp \u0111\u1ea7y \u0111\u1ee7, l\xfac \u0111\xf3 b\u1ea1n c\xf3 th\u1ec3 quay l\u1ea1i qu\xe1 tr\xecnh th\u1eed nghi\u1ec7m c\xe1c m\xf4 h\xecnh.\\r\\n\\r\\n## Vi\xea\u0301t ma\u0303 t\u01b0\u0323 \u0111\xf4\u0323ng va\u0300 co\u0301 th\xea\u0309 ta\u0301i s\u01b0\u0309 du\u0323ng \u0111\u01b0\u01a1\u0323c\\r\\n\\r\\nM\xf4\u0323t l\xf4\u0303i khi\xea\u0301n ba\u0323n m\xe2\u0301t nhi\xea\u0300u th\u01a1\u0300i gian khi la\u0300m d\u01b0\u0323 a\u0301n Data Science la\u0300 vi\xea\u0323c vi\xea\u0301t ma\u0303 kh\xf4ng ta\u0301i s\u01b0\u0309 du\u0323ng \u0111\u01b0\u01a1\u0323c. Mi\u0300nh \u0111a\u0303 g\u0103\u0323p r\xe2\u0301t nhi\xea\u0300u ba\u0323n background non-IT vi\xea\u0301t nh\u01b0\u0303ng do\u0300ng code ma\u0300 kh\xf4ng \u0111o\u0301ng go\u0301i la\u0323i tha\u0300nh ca\u0301c function.\\r\\n\\r\\nH\xe2\u0300u h\xea\u0301t ca\u0301c ba\u0323n s\u01b0\u0309 du\u0323ng Jupyter Notebook va\u0300 vi\xea\u0301t ca\u0301c do\u0300ng x\u01b0\u0309 ly\u0301 d\u01b0\u0303 li\xea\u0323u theo ca\u0301ch line-by-line. Vi\xea\u0323c vi\xea\u0301t code nh\u01b0 th\xea\u0301 na\u0300y se\u0303 la\u0300m m\xe2\u0301t kha\u0301 nhi\xea\u0300u th\u01a1\u0300i gian khi ba\u0323n x\u01b0\u0309 ly\u0301 t\u01b0\u01a1ng t\u01b0\u0323 cho ca\u0301c chi\xea\u0300u d\u01b0\u0303 li\xea\u0323u. Th\xf4ng th\u01b0\u01a1\u0300ng ca\u0301c ba\u0323n hay copy nguy\xean \u0111oa\u0323n code l\u0103\u0323p la\u0323i va\u0300 thay t\xean chi\xea\u0300u d\u01b0\u0303 li\xea\u0323u \u0111\xea\u0309 x\u01b0\u0309 ly\u0301, vi\xea\u0323c la\u0300m na\u0300y cu\u0303ng na\u0309y sinh v\xe2\u0301n \u0111\xea\u0300 khi ba\u0323n mu\xf4\u0301n c\xe2\u0323p nh\xe2\u0323t ph\u01b0\u01a1ng pha\u0301p x\u01b0\u0309 ly\u0301 m\u01a1\u0301i, ba\u0323n pha\u0309i s\u01b0\u0309a t\xe2\u0301t ca\u0309 nh\u01b0\u0303ng \u0111oa\u0323n code \\"copy\\" \xe2\u0301y va\u0300 vi\xea\u0323c ba\u0323n bo\u0309 so\u0301t vi\xea\u0323c c\xe2\u0323p nh\xe2\u0323t co\u0301 th\xea\u0309 se\u0303 co\u0300n la\u0300m t\xf4\u0301n th\u01a1\u0300i gian nhi\xea\u0300u h\u01a1n ba\u0323n vi\xea\u0301t **function**\\r\\n\\r\\nD\u1eef li\u1ec7u th\u1ef1c t\u1ebf \u0111\xf4i khi g\u1eb7p ph\u1ea3i sai s\xf3t do qu\xe1 tr\xecnh ng\u01b0\u1eddi d\xf9ng nh\u1eadp sai, v\xe0 d\u1eef li\u1ec7u n\xe0y b\u1ea1n th\u01b0\u1eddng s\u1eed d\u1ee5ng cho nhi\u1ec1u d\u1ef1 \xe1n kh\xe1c nhau. B\u1ea1n kh\xf4ng th\u1ec3 ph\xe0n n\xe0n v\u1edbi \u0111\u1ed9i d\u1eef li\u1ec7u r\u1eb1ng d\u1eef li\u1ec7u trong b\u1ea3ng b\u1ecb sai v\xe0 b\u1eaft h\u1ecd c\u1eadp nh\u1eadt l\u1ea1i d\u1eef li\u1ec7u cho b\u1ea1n \u0111\u1ec3 sau n\xe0y b\u1ea1n d\xf9ng kh\xf4ng sai n\u1eefa, \u0111i\u1ec1u n\xe0y kh\xe1 t\u1ed1n th\u1eddi gian v\xe0 c\xf4ng s\u1ee9c (D\u0129 nhi\xean theo quy t\u1eafc l\xe0 ph\u1ea3i c\u1eadp nh\u1eadt d\u1eef li\u1ec7u b\u1ecb sai v\xe0o b\u1ea3ng r\u1ed3i). Do \u0111\xf3 b\u1ea1n c\u1ea7n vi\u1ebft c\xe1c function x\u1eed l\xfd l\u1ed7i sai n\xe0y \u0111\u1ec3 t\xe1i s\u1eed d\u1ee5ng. V\xed d\u1ee5 nh\u01b0 ng\u01b0\u1eddi d\xf9ng nh\u1eadp tu\u1ed5i c\u1ee7a kh\xe1ch h\xe0ng l\xe0 130 hay 1 tu\u1ed5i, b\u1ea1n c\xf3 th\u1ec3 vi\u1ebft th\xe0nh m\u1ed9t function x\u1eed l\xfd cho c\u1ed9t d\u1eef li\u1ec7u tu\u1ed5i v\xe0 c\xf3 th\u1ec3 \u0111\xf3ng g\xf3i n\xf3 th\xe0nh package \u0111\u1ec3 t\xe1i s\u1eed d\u1ee5ng trong c\xe1c d\u1ef1 \xe1n kh\xe1c c\u1ea7n t\u1edbi c\u1ed9t tu\u1ed5i.\\r\\n\\r\\n\\r\\nKhi x\xe2y d\u01b0\u0323ng m\xf4 hi\u0300nh, ba\u0323n n\xean du\u0300ng ca\u0301c th\u01b0 vi\xea\u0323n nh\u01b0 Sklearn, LightGBM ... \u0111\xea\u0309 hu\xe2\u0301n luy\xea\u0323n m\xf4 hi\u0300nh m\xf4\u0323t ca\u0301ch nhanh cho\u0301ng thay vi\u0300 vi\xea\u0301t la\u0323i ca\u0301c thu\xe2\u0323t toa\u0301n t\u01b0\u0300 \u0111\xe2\u0300u. Ngoa\u0300i ra, ca\u0301c ba\u0323n co\u0301 th\xea\u0309 s\u01b0\u0309 du\u0323ng ca\u0301c th\u01b0 vi\xea\u0323n nh\u01b0 **pycaret**, **autogluon** \u0111\xea\u0309 th\u01b0\u0323c hi\xea\u0323n hu\xe2\u0301n luy\xea\u0323n t\u01b0\u0323 \u0111\xf4\u0323ng. Ca\u0301c th\u01b0 vi\xea\u0323n na\u0300y h\xf4\u0303 tr\u01a1\u0323 cha\u0323y nhi\xea\u0300u thu\xe2\u0323t toa\u0301n kha\u0301c nhau m\xf4\u0323t ca\u0301ch t\u01b0\u0323 \u0111\xf4\u0323ng, qua \u0111o\u0301 giu\u0301p ba\u0323n gia\u0309m thi\xea\u0309u th\u01a1\u0300i gian vi\xea\u0301t code t\u01b0\u0300ng thu\xe2\u0323t toa\u0301n va\u0300 so sa\u0301nh k\xea\u0301t qua\u0309 v\u01a1\u0301i nhau \u0111\xea\u0309 cho\u0323n thu\xe2\u0323t toa\u0301n na\u0300o t\xf4\u0301i \u01b0u.\\r\\n\\r\\n![](https://www.kdnuggets.com/wp-content/uploads/pycaret-automl-0.jpg)\\r\\n\\r\\n\\r\\n\u0110\u1ed1i v\u1edbi vi\u1ec7c tr\xecnh b\xe0y b\xe1o c\xe1o, b\u1ea1n c\u1ea7n chu\u1ea9n b\u1ecb template s\u1eb5n c\xe1c b\u01b0\u1edbc tr\xecnh b\xe0y c\u1ee7a m\u1ed9t d\u1ef1 \xe1n Data Science, vi\u1ec7c n\xe0y gi\xfap gi\u1ea3m thi\u1ec3u th\u1eddi gian chu\u1ea9n b\u1ecb b\xe1o c\xe1o c\u1ee7a b\u1ea1n. M\u1ed9t \u0111i\u1ec1u m\xecnh r\xfat ra trong qu\xe1 tr\xecnh b\xe1o c\xe1o d\u1ef1 \xe1n Khoa h\u1ecdc d\u1eef li\u1ec7u v\xe0 c\u0169ng l\xe0 s\u1ef1 kh\xe1c bi\u1ec7t \u0111\u1ed1i v\u1edbi hai lo\u1ea1i h\xecnh C\xf4ng ty Production v\xe0 Outsourcing \u0111\xf3 l\xe0 c\xe1c c\xf4ng ty Production chu\u1ed9ng c\xe1c bi\u1ec3u \u0111\u1ed3 \u0111\u01a1n gi\u1ea3n v\xe0 t\u1eadp trung v\xe0o k\u1ebft qu\u1ea3 c\u1ee7a d\u1eef li\u1ec7u, b\u1ea1n c\xf3 th\u1ec3 tr\xecnh b\xe0y m\u1ed9t slide kh\xf4ng c\u1ea7n qu\xe1 \u0111\u1eb9p, mi\u1ec5n s\u1ed1 li\u1ec7u l\xe0 ch\xednh x\xe1c v\xe0 h\u1ee3p l\xfd. Ng\u01b0\u1ee3c l\u1ea1i \u0111\u1ed1i v\u1edbi c\xf4ng ty Outsourcing th\xec ng\u01b0\u1eddi nghe c\u1ee7a b\u1ea1n l\xe0 Kh\xe1ch h\xe0ng b\xean ngo\xe0i v\xe0 c\u1ea7n tr\xecnh b\xe0y n\u1ed9i dung m\u1ed9t c\xe1ch b\u1eaft m\u1eaft, do \u0111\xf3 vi\u1ec7c chu\u1ea9n b\u1ecb template tr\u01b0\u1edbc l\xe0 r\u1ea5t c\u1ea7n thi\u1ebft.\\r\\n\\r\\nKhi x\xe2y d\u1ef1ng service, vi\u1ec7c vi\u1ebft m\xe3 c\xf3 th\u1ec3 t\xe1i s\u1eed d\u1ee5ng \u0111\u01b0\u1ee3c l\xe0 m\u1ed9t y\xeau c\u1ea7u g\u1ea7n nh\u01b0 l\xe0 b\u1eaft bu\u1ed9c. Nh\u01b0 ph\u1ea7n tr\xean m\xecnh \u0111\xe3 \u0111\u1ec1 c\u1eadp, ch\xfang ta x\xe2y d\u1ef1ng service ngay khi c\xf3 m\xf4 h\xecnh c\u01a1 b\u1ea3n, do \u0111\xf3 khi x\xe2y d\u1ef1ng c\xe1c m\xf4 h\xecnh ph\u1ee9c t\u1ea1p h\u01a1n, c\xe1c b\u1ea1n c\u1ea7n ph\u1ea3i x\xe2y d\u1ef1ng c\xe1c ph\u01b0\u01a1ng th\u1ee9c, c\xe1c module sao cho khi service g\u1ecdi c\xe1c m\xf4 h\xecnh ph\u1ee9c t\u1ea1p \u0111\xf3 kh\xf4ng n\u1ea3y sinh ra l\u1ed7i. B\u1ea1n c\xf3 th\u1ec3 th\u1ea5y trong th\u01b0 vi\u1ec7n sklearn hay nh\u1eefng th\u01b0 vi\u1ec7n kh\xe1c khi d\u1ef1 \u0111o\xe1n m\xf4 h\xecnh \u0111\u1ec1u g\u1ecdi ph\u01b0\u01a1ng th\u1ee9c **predict**, \u0111i\u1ec1u n\xe0y gi\xfap ch\xfang ta d\u1ec5 qu\u1ea3n l\xfd h\u01a1n khi x\xe2y d\u1ef1ng c\xe1c thu\u1eadt to\xe1n kh\xe1c nhau. V\xec v\u1eady m\u1ed9t l\u1eddi khuy\xean m\xecnh d\xe0nh cho c\xe1c b\u1ea1n l\xe0 h\xe3y d\xe0nh th\u1eddi gian \xedt nh\u1ea5t m\u1ed9t th\xe1ng \u0111\u1ec3 h\u1ecdc L\u1eadp tr\xecnh h\u01b0\u1edbng \u0111\u1ed1i t\u01b0\u1ee3ng \u0111\u1ec3 c\xf3 th\u1ec3 hi\u1ec3u r\xf5 h\u01a1n.\\r\\n\\r\\n## Ch\xfang ta kh\xf4ng l\xe0m vi\u1ec7c m\u1ed9t m\xecnh"},{"id":"10-loi-sai-visualization","metadata":{"permalink":"/blog/10-loi-sai-visualization","source":"@site/blog/2024/03/04/2024-03-04-pitfall-visualize.md","title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","description":"This is my first post on Docusaurus.","date":"2024-03-04T00:00:00.000Z","formattedDate":"4 th\xe1ng 3, 2024","tags":[{"label":"data visualization","permalink":"/blog/tags/data-visualization"},{"label":"histogram","permalink":"/blog/tags/histogram"},{"label":"seaborn","permalink":"/blog/tags/seaborn"},{"label":"plot","permalink":"/blog/tags/plot"}],"readingTime":2.56,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","description":"This is my first post on Docusaurus.","slug":"10-loi-sai-visualization","authors":"lhduc","tags":["data visualization","histogram","seaborn","plot"],"image":"https://clauswilke.com/dataviz/pitfalls_of_color_use_files/figure-html/popgrowth-US-rainbow-1.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Data Scientist se\u0303 la\u0300m gi\u0300 khi bi\u0323 a\u0301p deadline","permalink":"/blog/Data-Scientist-se-lam-gi-khi-bi-ap-deadline"},"nextItem":{"title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","permalink":"/blog/cach-bieu-dien-histogram"}},"content":"Th\xf4ng th\u01b0\u01a1\u0300ng, khi visualize m\u0103\u0323c \u0111i\u0323nh histogram cu\u0309a seaborn se\u0303 kh\xf4ng th\xea\u0309 hi\xea\u0323n t\xe2\u0301t ca\u0309 ca\u0301c nha\u0303n cu\u0309a bins va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng m\xf4\u0303i bin\\r\\nV\u01a1\u0301i ca\u0301ch la\u0300m nh\u01b0 tr\xean se\u0303 r\xe2\u0301t kho\u0301 theo do\u0303i ca\u0301c khoa\u0309ng gia\u0301 tri\u0323 cu\u0309a t\u01b0\u0300ng bin va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng cu\u0309a bin \u0111o\u0301. May m\u0103\u0301n thay seaborn histogram t\u01b0\u01a1ng t\u01b0\u0323 numpy n\xean ta co\u0301 th\xea\u0309 du\u0300ng ha\u0300m np.histogram \u0111\xea\u0309 gia\u0309i quy\xea\u0301t v\xe2\u0301n \u0111\xea\u0300 na\u0300y\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## D\xe2\u0301u hi\xea\u0323u cu\u0309a m\xf4\u0323t bi\xea\u0309u \u0111\xf4\u0300 tr\u01b0\u0323c quan ke\u0301m \\r\\n\\r\\n- D\u01b0\u0303 li\xea\u0323u li\xean quan bi\u0323 \xe2\u0309n: Nh\u01b0\u0303ng th\xf4ng tin c\xe2\u0300n thi\xea\u0301t bi\u0323 che khu\xe2\u0301t ho\u0103\u0323c kh\xf4ng \u0111\u01b0\u01a1\u0323c \u0111a\u0301nh d\xe2\u0301u\\r\\n- Bi\xea\u0309u \u0111\xf4\u0300 qua\u0301 ta\u0309i: Bao g\xf4\u0300m qua\u0301 nhi\xea\u0300u th\xf4ng tin khi\xea\u0301n bi\xea\u0309u \u0111\xf4\u0300 kho\u0301 \u0111o\u0323c\\r\\n- Sai l\xea\u0323ch d\u01b0\u0303 li\xea\u0323u: S\u01b0\u0309 du\u0323ng ti\u0309 l\xea\u0323  ho\u0103\u0323c \u0111i\u0323nh da\u0323ng d\u01b0\u0303 li\xea\u0323u sai\\r\\n- M\xf4 ta\u0309 d\u01b0\u0303 li\xea\u0323u sai: M\xf4 ta\u0309 d\u01b0\u0303 li\xea\u0323u kh\xf4ng \u0111u\u0301ng v\u01a1\u0301i hi\u0300nh ve\u0303\\r\\n- Hi\u0300nh a\u0309nh kho\u0301 hi\xea\u0309u: Thi\xea\u0301t k\xea\u0301 hi\u0300nh a\u0309nh g\xe2y kho\u0301 hi\xea\u0309u la\u0300m cho ng\u01b0\u01a1\u0300i \u0111o\u0323c kh\xf4ng n\u0103\u0301m \u0111\u01b0\u01a1\u0323c th\xf4ng tin\\r\\n\\r\\n## \u0110\xf4\u0323 t\u01b0\u01a1ng pha\u0309n ma\u0300u g\xe2y hi\xea\u0309u l\xe2\u0300m\\r\\n\\r\\n**\u0110\u01b0a qua\u0301 nhi\xea\u0300u th\xf4ng tin kh\xf4ng li\xean quan**\\r\\n\\r\\nM\xf4\u0323t sai l\xe2\u0300m ph\xf4\u0309 bi\xea\u0301n la\u0300 \u0111\u01b0a qua\u0301 nhi\xea\u0300u ma\u0300u va\u0300o visualize. Vi\u0301 du\u0323 ve\u0303 bi\xea\u0309u \u0111\xf4\u0300 scatter plot v\xea\u0300 d\xe2n s\xf4\u0301 va\u0300 t\xf4\u0301c \u0111\xf4\u0323 t\u0103ng tr\u01b0\u01a1\u0309ng d\xe2n s\xf4\u0301 cu\u0309a Vi\xea\u0323t Nam, v\u01a1\u0301i 63 ti\u0309nh tha\u0300nh ta co\u0301 63 ma\u0300u cho m\xf4\u0303i ti\u0309nh, \u0111i\xea\u0300u na\u0300y g\xe2y ra v\xe2\u0301n \u0111\xea\u0300 kho\u0301 kh\u0103n khi nh\xe2\u0323n bi\xea\u0301t ma\u0300u na\u0300o la\u0300 cu\u0309a ti\u0309nh tha\u0300nh na\u0300o. Theo nguy\xean t\u0103\u0301c chung, thang ma\u0300u ch\xe2\u0301t l\u01b0\u01a1\u0323ng hoa\u0323t \u0111\xf4\u0323ng t\xf4\u0301t nh\xe2\u0301t khi co\u0301 ba \u0111\xea\u0301n n\u0103m loa\u0323i ma\u0300u kha\u0301c nhau. Do \u0111o\u0301, thay vi\u0300 \u0111\xea\u0309 63 ma\u0300u cho 63 ti\u0309nh tha\u0300nh, chu\u0301ng ta n\xean ph\xe2n chia ma\u0300u theo 7 khu v\u01b0\u0323c kinh t\xea\u0301 (ho\u0103\u0323c 3 mi\xea\u0300n) va\u0300 \u0111\xea\u0309 xa\u0301c \u0111i\u0323nh t\u01b0\u0300ng ti\u0309nh tha\u0300nh, chu\u0301ng ta th\xeam ca\u0301c nha\u0303n ti\u0309nh tha\u0300nh va\u0300o bi\xea\u0309u \u0111\xf4\u0300. Di\u0303 nhi\xean chu\u0301ng ta kh\xf4ng c\xe2\u0300n pha\u0309i th\xeam t\xe2\u0301t ca\u0309 ca\u0301c nha\u0303n cu\u0309a t\xe2\u0301t ca\u0309 ti\u0309nh tha\u0300nh va\u0300o bi\xea\u0309u \u0111\xf4\u0300 ma\u0300 chi\u0309 c\xe2\u0300n th\xeam m\xf4\u0323t va\u0300i nha\u0303n ti\xeau bi\xea\u0309u \u01b0\u0301ng v\u01a1\u0301i t\u01b0\u0300ng khu v\u01b0\u0323c. Ngoa\u0300i ra, chu\u0301ng ta c\xe2\u0300n n\xean ke\u0300m theo d\u01b0\u0303 li\xea\u0323u da\u0323ng ba\u0309ng v\u01a1\u0301i ca\u0301c th\xf4ng tin \u0111\xe2\u0300y \u0111u\u0309 \u0111\xea\u0309 ng\u01b0\u01a1\u0300i \u0111o\u0323c co\u0301 th\xea\u0309 truy c\xe2\u0323p toa\u0300n b\xf4\u0323 d\u01b0\u0303 li\xea\u0323u.\\r\\n\\r\\n\\r\\n\u0110\xf4\u0301i v\u01a1\u0301i da\u0323ng barchart vi\xea\u0323c s\u01b0\u0309 du\u0323ng qua\u0301 nhi\xea\u0300u ma\u0300u s\u0103\u0301c(ma\u0300u c\xe2\u0300u v\xf4\u0300ng) kh\xf4ng th\xea\u0309 hi\xea\u0323n \u0111\u01b0\u01a1\u0323c mu\u0323c \u0111i\u0301ch cu\u0309a ma\u0300u s\u0103\u0301c trong bi\xea\u0309u \u0111\xf4\u0300 na\u0300y\\r\\n\\r\\n![image](https://clauswilke.com/dataviz/pitfalls_of_color_use_files/figure-html/popgrowth-US-rainbow-1.png)\\r\\n\\r\\n\\r\\n**S\u01b0\u0309 du\u0323ng thang ma\u0300u kh\xf4ng \u0111\u01a1n \u0111i\xea\u0323u(non-monotonic) \u0111\xea\u0309 ma\u0303 ho\u0301a gia\u0301 tri\u0323 d\u01b0\u0303 li\xea\u0323u**\\r\\n\\r\\n**Kh\xf4ng thi\xea\u0301t k\xea\u0301 ma\u0300u cho ng\u01b0\u01a1\u0300i gia\u0309m thi\u0323 l\u01b0\u0323c ma\u0300u s\u0103\u0301c**\\r\\n\\r\\nhttps://clauswilke.com/dataviz/color-pitfalls.html\\r\\n\\r\\n\\r\\n**Ta\u0301c \u0111\xf4\u0323ng cu\u0309a l\xf4\u0303i**\\r\\n\\r\\n- Ng\u01b0\u01a1\u0300i du\u0300ng hi\xea\u0309u nh\xe2\u0300m gia\u0301 tri\u0323 na\u0300o quan tro\u0323ng h\u01a1n\\r\\n- M\xe2\u0301t th\u01a1\u0300i gian \u0111\xea\u0309 hi\xea\u0309u th\xf4ng tin\\r\\n\\r\\n**Ca\u0301ch gia\u0309i quy\xea\u0301t**\\r\\n\\r\\n- S\u01b0\u0309 du\u0323ng da\u0309i ma\u0300u ng\u0103\u0301n \u0111\xea\u0309 hi\xea\u0309n thi\u0323 gia\u0301 tri\u0323 cao h\u01a1n gia\u0301 tri\u0323 kha\u0301c (vi\u0301 du\u0323 \u0111o\u0309 -> va\u0300ng)\\r\\n- Ca\u0301ch \u0111\u01a1n gia\u0309n nh\xe2\u0301t la\u0300 chuy\xea\u0309n da\u0300i ma\u0300u \u0111o\u0301 v\xea\u0300 m\u01b0\u0301c xa\u0301m xem ma\u0300u ba\u0323n cho\u0323n co\u0301 th\xea\u0309 hi\xea\u0323n s\u01b0\u0323 kha\u0301c bi\xea\u0323t kh\xf4ng\\r\\n- S\u01b0\u0309 du\u0323ng t\xf4ng ma\u0300u no\u0301ng/la\u0323nh \u0111\xea\u0309 th\xea\u0309 hi\xea\u0323n gia\u0301 tri\u0323 \u0111\xf4\u0301i nghi\u0323ch (ti\xeau c\u01b0\u0323c/ti\u0301ch c\u01b0\u0323c)"},{"id":"cach-bieu-dien-histogram","metadata":{"permalink":"/blog/cach-bieu-dien-histogram","source":"@site/blog/2024/02/18/2024-02-18-visual-histogram.md","title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","description":"This is my first post on Docusaurus.","date":"2024-02-18T00:00:00.000Z","formattedDate":"18 th\xe1ng 2, 2024","tags":[{"label":"data visualization","permalink":"/blog/tags/data-visualization"},{"label":"histogram","permalink":"/blog/tags/histogram"},{"label":"seaborn","permalink":"/blog/tags/seaborn"},{"label":"plot","permalink":"/blog/tags/plot"}],"readingTime":2.025,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","description":"This is my first post on Docusaurus.","slug":"cach-bieu-dien-histogram","authors":"lhduc","tags":["data visualization","histogram","seaborn","plot"],"keywords":["data visualization","histogram","seaborn","plot"],"image":"https://datasciencedances.com/assets/images/1709112253837-1fa0ac6a6387c91756523efa79c896c0.jpg","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"10 l\xf4\u0303i sai trong data visualization va\u0300 ca\u0301ch pho\u0300ng tra\u0301nh","permalink":"/blog/10-loi-sai-visualization"},"nextItem":{"title":"Data Envelopment Analysis","permalink":"/blog/data-envelopment-analysis-phan-tich-hieu-suat"}},"content":"Th\xf4ng th\u01b0\u01a1\u0300ng, khi visualize m\u0103\u0323c \u0111i\u0323nh histogram cu\u0309a seaborn se\u0303 kh\xf4ng th\xea\u0309 hi\xea\u0323n t\xe2\u0301t ca\u0309 ca\u0301c nha\u0303n cu\u0309a bins va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng m\xf4\u0303i bin\\r\\nV\u01a1\u0301i ca\u0301ch la\u0300m nh\u01b0 tr\xean se\u0303 r\xe2\u0301t kho\u0301 theo do\u0303i ca\u0301c khoa\u0309ng gia\u0301 tri\u0323 cu\u0309a t\u01b0\u0300ng bin va\u0300 s\xf4\u0301 l\u01b0\u01a1\u0323ng cu\u0309a bin \u0111o\u0301. May m\u0103\u0301n thay seaborn histogram t\u01b0\u01a1ng t\u01b0\u0323 numpy n\xean ta co\u0301 th\xea\u0309 du\u0300ng ha\u0300m np.histogram \u0111\xea\u0309 gia\u0309i quy\xea\u0301t v\xe2\u0301n \u0111\xea\u0300 na\u0300y\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\nD\u01b0\u1edbi \u0111\xe2y l\xe0 v\xed d\u1ee5 c\u01a1 b\u1ea3n khi visualize d\u1eef li\u1ec7u b\u1eb1ng histogram m\u1eb7c \u0111\u1ecbnh c\u1ee7a seaborn\\r\\n\\r\\n```python\\r\\nimport numpy as np\\r\\nimport seaborn as sns \\r\\nnp.random.seed(42)\\r\\nx = np.random.uniform(size=200)\\r\\nsns.histplot(x, bins=10)\\r\\n```\\r\\n\\r\\n![Example banner](1709112253837.jpg)\\r\\n\\r\\nK\u1ebft qu\u1ea3 kh\xf4ng cho ta th\u1ea5y \u0111\u01b0\u1ee3c bin \u0111\u1ea7u ti\xean n\u1eb1m trong kho\u1ea3ng gi\xe1 tr\u1ecb n\xe0o, v\xe0 s\u1ed1 l\u01b0\u1ee3ng ph\u1ea7n t\u1eed l\xe0 bao nhi\xeau, \u0111i\u1ec1u n\xe0y d\u1eabn \u0111\u1ebfn kh\xf3 kh\u0103n \u0111\u1ec3 hi\u1ec3u \u0111\u01b0\u1ee3c bi\u1ec3u \u0111\u1ed3 c\u0169ng nh\u01b0 \u0111\xe1nh gi\xe1 k\u1ebft qu\u1ea3. \u0110\u1ec3 gi\u1ea3i quy\u1ebft v\u1ea5n \u0111\u1ec1 tr\xean, ch\xfang ta t\xecm c\xe1ch \u0111i\u1ec1n v\xe0o bi\u1ec3u \u0111\u1ed3 b\u1eb1ng ph\u01b0\u01a1ng th\u1ee9c `plt.text`. Tr\u01b0\u1edbc h\u1ebft, ch\xfang ta c\u1ea7n t\xednh \u0111\u01b0\u1ee3c kho\u1ea3ng m\u1ed7i bin v\xe0 s\u1ed1 l\u01b0\u1ee3ng c\xe1c ph\u1ea7n t\u1eed trong bin, may m\u1eafn thay np.histogram c\xf3 th\u1ec3 gi\xfap ta t\xednh \u0111\u01b0\u1ee3c c\xe1c gi\xe1 tr\u1ecb n\xe0y\\r\\n\\r\\n```python\\r\\ncounts, bin_labels = np.histogram(x, bins=10)\\r\\nprint(len(counts), counts)\\r\\nprint(len(bin_labels), bin_labels)\\r\\n```\\r\\n\\r\\n```\\r\\n10 [22 24 20 24 11 19 20 18 18 24]\\r\\n11 [0.00552212 0.1036586  0.20179508 0.29993156 0.39806804 0.49620453\\r\\n 0.59434101 0.69247749 0.79061397 0.88875045 0.98688694]\\r\\n```\\r\\n\\r\\nCa\u0301c ba\u0323n co\u0301 th\xea\u0309 th\xe2\u0301y v\u01a1\u0301i tham s\xf4\u0301 bins \u0111\u01b0a va\u0300o chi\u0309 co\u0301 10 trong khi k\xea\u0301t qua\u0309 nha\u0303n bin_labels la\u0323i co\u0301 11 gia\u0301 tri\u0323, trong \u0111o\u0301 gia\u0301 tri\u0323 \u0111\xe2\u0300u la\u0300 gia\u0301 tri\u0323 nho\u0309 nh\xe2\u0301t cu\u0309a x va\u0300 gia\u0301 tri\u0323 cu\xf4\u0301i la\u0300 gia\u0301 tri\u0323 cao nh\xe2\u0301t cu\u0309a x. Do \u0111o\u0301 khoa\u0309ng \u0111\xe2\u0300u ti\xean cu\u0309a bin \u0111\xe2\u0300u ti\xean co\u0301 gia\u0301 tri\u0323 n\u0103\u0300m t\u01b0\u0300 [0.00552212, 0.1036586)\\r\\n\u0110\xea\u0309 ki\xea\u0309m tra xem co\u0301 \u0111u\u0301ng th\xea\u0309 kh\xf4ng, vi\u0301 du\u0323 ki\xea\u0309m tra bin \u0111\xe2\u0300u ti\xean co\u0301 pha\u0309i 22 ph\xe2\u0300n t\u01b0\u0309 kh\xf4ng?\\r\\n\\r\\n```python\\r\\nlen(x[(x>=bin_labels[0]) & (x<bin_labels[1])])\\r\\n```\\r\\n\\r\\n```\\r\\n22\\r\\n```\\r\\n\\r\\nSau \u0111o\u0301, ta du\u0300ng matplotlib \u0111\xea\u0309 plot text\\r\\n\\r\\n```python\\r\\nimport matplotlib.pyplot as plt \\r\\n\\r\\nax = sns.histplot(x, bins=10)\\r\\nbin_heights = [p.get_height() if p.get_height() > 0 else 0.1 for p in ax.patches]\\r\\n# Hi\u1ec3n th\u1ecb gi\xe1 tr\u1ecb count t\u1eebng bin\\r\\nfor i in range(len(bin_heights)):\\r\\n    plt.text(ax.patches[i].get_x() + ax.patches[i].get_width() / 2,\\r\\n            bin_heights[i],\\r\\n            str(int(bin_heights[i])),\\r\\n            fontsize=14,\\r\\n            ha=\'center\',\\r\\n            va=\'bottom\')\\r\\nmids = [rect.get_x() + rect.get_width() / 2 for rect in ax.patches]\\r\\nlabels = [(round(i,2),round(j,2)) for i,j in zip(bin_labels[:-1], bin_labels[1:])]\\r\\nax.set_xticks(mids, labels=labels, fontsize=14, rotation=90)\\r\\nax.set_ylim(0,28)\\r\\n```\\r\\n\\r\\n![Example banner](1709112655963.png)"},{"id":"data-envelopment-analysis-phan-tich-hieu-suat","metadata":{"permalink":"/blog/data-envelopment-analysis-phan-tich-hieu-suat","source":"@site/blog/2024/01/15/2024-01-15-Data-Envelopment-Analysis.md","title":"Data Envelopment Analysis","description":"Ph\xe2n ti\u0301ch hi\xea\u0323u su\xe2\u0301t.","date":"2024-01-15T00:00:00.000Z","formattedDate":"15 th\xe1ng 1, 2024","tags":[{"label":"data visualization","permalink":"/blog/tags/data-visualization"},{"label":"histogram","permalink":"/blog/tags/histogram"},{"label":"seaborn","permalink":"/blog/tags/seaborn"},{"label":"plot","permalink":"/blog/tags/plot"}],"readingTime":1.29,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Data Envelopment Analysis","description":"Ph\xe2n ti\u0301ch hi\xea\u0323u su\xe2\u0301t.","slug":"data-envelopment-analysis-phan-tich-hieu-suat","authors":"lhduc","tags":["data visualization","histogram","seaborn","plot"],"keywords":["data visualization","histogram","seaborn","plot"],"image":"https://i.imgur.com/mErPwqL.png","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Ca\u0301ch bi\xea\u0309u di\xea\u0303n s\xf4\u0301 l\u01b0\u01a1\u0323ng va\u0300 khoa\u0309ng d\u01b0\u0303 li\xea\u0323u cho Histogram du\u0300ng Seaborn va\u0300 Numpy","permalink":"/blog/cach-bieu-dien-histogram"},"nextItem":{"title":"Covariance va\u0300 Correlation","permalink":"/blog/covariance-correlation"}},"content":"**\u0110a\u0301nh gia\u0301 Hi\xea\u0323u su\xe2\u0301t la\u0300 gi\u0300\u200b?**\\r\\n\\r\\nKhi chu\u0301ng ta co\u0301 \u0111\xe2\u0300u va\u0300o, va\u0300 nh\xe2\u0323n \u0111\u01b0\u01a1\u0323c k\xea\u0301t qua\u0309, chu\u0301ng ta hay \u0111a\u0301nh gia\u0301 hi\xea\u0323u su\xe2\u0301t cu\u0309a k\xea\u0301t qua\u0309 xem v\u01a1\u0301i \u0111\xe2\u0300u va\u0300o nh\u01b0 th\xea\u0301 thi\u0300 k\xea\u0301t qua\u0309 li\xea\u0323u co\u0301 t\xf4\u0301t kh\xf4ng.\u200b M\xf4\u0323t s\xf4\u0301 vi\u0301 du\u0323 c\u01a1 ba\u0309n: Gia\u0301 tha\u0300nh/sa\u0309n ph\xe2\u0309m, L\u01a1\u0323i nhu\xe2\u0323n/sa\u0309n ph\xe2\u0309m.\u200b\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n$$\\r\\n\\\\frac{Output}{Input}\\r\\n$$\\r\\n\\r\\nC\xf4ng th\u01b0\u0301c tr\xean \u0111\u01b0\u01a1\u0323c go\u0323i la\u0300 th\u01b0\u01a1\u0301c \u0111o hi\xea\u0323u qua\u0309.\u200b\\r\\nChu\u0301ng ta co\u0301 th\xea\u0309 m\u01a1\u0309 r\xf4\u0323ng c\xf4ng th\u01b0\u0301c tr\xean v\u01a1\u0301i Nhi\xea\u0300u \u0111\xe2\u0300u va\u0300o (Inputs) va\u0300 nhi\xea\u0300u \u0111\xe2\u0300u ra (Outputs)\u200b\\r\\n\\r\\n![](efficient_frontier.png)\\r\\n\u0110\xf4\u0323 d\xf4\u0301c cu\u0309a \u0111\u01b0\u01a1\u0300ng n\xf4\u0301i v\u01a1\u0301i m\xf4\u0303i \u0111i\xea\u0309m va\u0300 g\xf4\u0301c to\u0323a \u0111\xf4\u0323 t\u01b0\u01a1ng \u01b0\u0301ng v\u01a1\u0301i Sales/ Employee ( hi\xea\u0323u qua\u0309).\u200b\\r\\n\\r\\n\u0110\u01b0\u01a1\u0300ng co\u0301 \u0111\xf4\u0323 d\xf4\u0301c cao nh\xe2\u0301t (n\xf4\u0301i v\u01a1\u0301i \u0111i\xea\u0309m B) \u0111\u01b0\u01a1\u0323c go\u0323i la\u0300 Efficient  Frontier (\u0110\u01b0\u01a1\u0300ng bi\xean hi\xea\u0323u qua\u0309).\u200b\\r\\n\\r\\nCa\u0301c \u0111i\xea\u0309m se\u0303 n\u0103\u0300m cu\u0300ng 1 phi\u0301a so v\u01a1\u0301i \u0111\u01b0\u01a1\u0300ng th\u0103\u0309ng, ho\u0103\u0323c \u01a1\u0309 tr\xean, ho\u0103\u0323c \u01a1\u0309 d\u01b0\u01a1\u0301i.\u200b\\r\\n\\r\\nVi\u0300 \u0111\u01b0\u01a1\u0300ng bi\xean na\u0300y bao bo\u0323c ca\u0301c \u0111i\xea\u0309m d\u01b0\u0303 li\xea\u0323u, n\xean ph\xe2n ti\u0301ch na\u0300y \u0111\u01b0\u01a1\u0323c go\u0323i la\u0300 Data Envelopment Analysis.\u200b\\r\\n\\r\\n\\r\\n\\r\\nChu\u0301ng ta co\u0301 th\xea\u0309  ve\u0303 m\xf4\u0323t \u0111\u01b0\u01a1\u0300ng th\xf4\u0301ng k\xea h\xf4\u0300i quy $y=0.622x$ \u0111\xea\u0309 \u01b0\u01a1\u0301c l\u01b0\u01a1\u0323ng m\xf4\u0301i quan h\xea\u0323 tuy\xea\u0301n ti\u0301nh gi\u01b0\u0303a input va\u0300 output.\u200b\\r\\n\\r\\n\u0110\u01b0\u01a1\u0300ng h\xf4\u0300i quy na\u0300y \u0111i qua chi\u0301nh gi\u01b0\u0303a cu\u0309a t\xe2\u0323p d\u01b0\u0303 li\xea\u0323u, do \u0111o\u0301 chu\u0301ng ta co\u0301 th\xea\u0309 xem ca\u0301c \u0111i\xea\u0309m \u01a1\u0309 phi\u0301a tr\xean \u0111\u01b0\u01a1\u0300ng la\u0300 hi\xea\u0323u qua\u0309 t\xf4\u0301t va\u0300 \u0111i\xea\u0309m d\u01b0\u01a1\u0301i la\u0300 ch\u01b0a t\xf4\u0301t, khoa\u0309ng ca\u0301ch gi\u01b0\u0303a \u0111i\xea\u0309m t\u01a1\u0301i \u0111\u01b0\u01a1\u0300ng h\xf4\u0300i quy chi\u0301nh ta m\u01b0\u0301c \u0111\xf4\u0323 hi\xea\u0323u qua\u0309/kh\xf4ng hi\xea\u0323u qua\u0309\u200b\\r\\n\\r\\nKhoa\u0309ng ca\u0301ch t\u01b0\u0300 ca\u0301c \u0111i\xea\u0309m \u0111\xea\u0301n \u0111\u01b0\u01a1\u0300ng Efficient Frontier n\xeau l\xean \u0111\xf4\u0323 l\xea\u0323ch so v\u01a1\u0301i \u0111i\xea\u0309m t\xf4\u0301t nh\xe2\u0301t\u200b\\r\\n\\r\\n![](efficiente_frontier_regression_line.png)"},{"id":"covariance-correlation","metadata":{"permalink":"/blog/covariance-correlation","source":"@site/blog/2020/06/15/2020-06-15-covariance-correlation.md","title":"Covariance va\u0300 Correlation","description":"Covariance va\u0300 Correlation.","date":"2020-06-15T00:00:00.000Z","formattedDate":"15 th\xe1ng 6, 2020","tags":[{"label":"math","permalink":"/blog/tags/math"},{"label":"correlation","permalink":"/blog/tags/correlation"},{"label":"covariance","permalink":"/blog/tags/covariance"}],"readingTime":3.175,"hasTruncateMarker":true,"authors":[{"name":"L\xea Hu\u1ef3nh \u0110\u1ee9c","title":"Data Scientist","url":"https://www.linkedin.com/in/lhduc94/","imageURL":"https://media.licdn.com/dms/image/C5603AQH9eWPFDpyAzA/profile-displayphoto-shrink_800_800/0/1621156513556?e=1715817600&v=beta&t=3tlR9YHGRdMNqnedzHomTZL2gt-Ln_KAz3bckjnBCKU","key":"lhduc"}],"frontMatter":{"title":"Covariance va\u0300 Correlation","description":"Covariance va\u0300 Correlation.","slug":"covariance-correlation","authors":"lhduc","tags":["math","correlation","covariance"],"image":"https://miro.medium.com/v2/resize:fit:720/format:webp/0*ww9NZU5NWGL4miVT","hide_table_of_contents":false},"unlisted":false,"prevItem":{"title":"Data Envelopment Analysis","permalink":"/blog/data-envelopment-analysis-phan-tich-hieu-suat"}},"content":"![](https://miro.medium.com/v2/resize:fit:720/format:webp/0*ww9NZU5NWGL4miVT)\\r\\n\\r\\nCovariance (Hi\u1ec7p ph\u01b0\u01a1ng sai) v\xe0 Correlation (H\u1ec7 s\u1ed1 t\u01b0\u01a1ng quan) l\xe0 hai kh\xe1i ni\u1ec7m trong l\u0129nh v\u1ef1c x\xe1c su\u1ea5t th\u1ed1ng k\xea. C\u1ea3 hai kh\xe1i ni\u1ec7m n\xe0y \u0111\u1ec1u n\xf3i v\u1ec1 m\u1ed1i quan h\u1ec7 gi\u1eefa hai bi\u1ebfn v\u1edbi nhau, hay n\xf3i c\xe1ch kh\xe1c hai ch\u1ec9 s\u1ed1 n\xe0y d\xf9ng \u0111\u1ec3 th\u1ec3 hi\u1ec7n s\u1ef1 ph\u1ee5 thu\u1ed9c gi\u1eefa hai bi\u1ebfn.\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n\\r\\n## Covariance l\xe0 g\xec?\\r\\nCovariance th\u1ec3 hi\u1ec7n m\u1ed1i quan h\u1ec7 gi\u1eefa hai bi\u1ebfn v\u1edbi nhau, c\xf3 th\u1ec3 l\xe0 \u0111\u1ed3ng bi\u1ebfn (positive covariance) ho\u1eb7c ngh\u1ecbch bi\u1ebfn (negative covariance).\\r\\n\\r\\n\u0110\u1ecbnh ngh\u0129a : Cho 2 bi\u1ebfn ng\u1eabu nhi\xean X, Y v\u1edbi k\xec v\u1ecdng $\\\\mu_X$ v\xe0 $\\\\mu_Y$  covariance c\u1ee7a X, Y \u0111\u01b0\u1ee3c t\xednh b\u1eb1ng c\xf4ng th\u1ee9c :\\r\\n\\r\\n$$\\r\\nCov(X, Y)=E[(X\u2212\\\\mu_X)*(Y\u2212\\\\mu_Y)]\\r\\n$$\\r\\nC\xe1c t\xednh ch\u1ea5t c\u1ee7a Covariance :\\r\\n\\r\\n1. $Cov(aX + b, cY + d)=acCov(X, Y)$ v\u1edbi $a, b, c, d$ cho tr\u01b0\u1edbc\\r\\n2. $Cov(X1 + X2 ,Y)=Cov(X1, Y) + Cov(X2, Y)$\\r\\n3. $Cov(X, X)=Var(X)$\\r\\n4. $Cov(X, Y)=E(XY)\u2212\\\\mu_X * \\\\mu_Y$\\r\\n5. $Var(X, Y)=Var(X) + Var(Y) + 2 * Cov(X, Y)$\\r\\n6. $X, Y$ \u0111\u1ed9c l\u1eadp th\xec $Cov(X, Y)=0$ .\\r\\n\\r\\nL\u01b0u \xfd :\\r\\n\\r\\nT\u1eeb $(3)$ v\xe0 $(4)$ ta c\xf3 $Var(X) = E(X^2) \u2212 (\\\\mu_X)^2$. N\u1ebfu X, Y \u0111\u1ed9c l\u1eadp t\u1eeb 5 c\xf3 th\u1ec3 suy ra \u0111\u01b0\u1ee3c $Var(X, Y)=Var(X) + Var(Y)$.\\r\\n\\r\\nV\u1edbi Ti\u0301nh ch\xe2\u0301t $(6)$, \u0111i\u1ec1u ng\u01b0\u1ee3c l\u1ea1i kh\xf4ng \u0111\xfang, ngh\u0129a l\xe0 $Cov(X, Y)=0$ kh\xf4ng c\xf3 ngh\u0129a l\xe0 X, Y \u0111\u1ed9c l\u1eadp v\u1edbi nhau. \\r\\nV\xed d\u1ee5 $X = [-2 , -1 , 1 , 2]$ v\xe0 $Y = X^2 = [4 , 1, 1 , 4]$ khi \u0111\xf3 $Cov(X, Y)=0$ m\u0103\u0323c du\u0300 X va\u0300 Y co\u0301 m\xf4\u0301i t\u01b0\u01a1ng quan v\u01a1\u0301i nhau\\r\\n\\r\\n## Correlation l\xe0 g\xec?\\r\\n\\r\\n\u0110\u1ec3 th\u1ec3 hi\u1ec7n m\u1ed1i quan h\u1ec7 gi\u1eefa 2 bi\u1ebfn l\xe0 \u201cm\u1ea1nh\u201d hay \u201cy\u1ebfu\u201d, ch\xfang ta s\u1eed d\u1ee5ng correlation thay cho covariance.\\r\\n\\r\\n\u0110\u1ecbnh ngh\u0129a : Correlation coefficient c\u1ee7a hai bi\u1ebfn X v\xe0 Y \u0111\u01b0\u1ee3c t\xednh theo c\xf4ng th\u1ee9c\\r\\n\\r\\n$$\\r\\nCor(X,Y) = \u03c1= Cov(X, Y) / (\\\\sigma_X * \\\\sigma_Y)\\r\\n$$\\r\\n\\r\\n\\r\\n**C\xe1c t\xednh ch\u1ea5t c\u1ee7a Correlation**\\r\\n\\r\\n1. Correlation l\xe0 Covariance \u0111\u01b0\u1ee3c chu\u1ea9n h\xf3a c\u1ee7a hai bi\u1ebfn X, Y\\r\\n\\r\\n2. Correlation th\u1ec3 hi\u1ec7n m\u1ed9t t\u1ec9 l\u1ec7, do \u0111\xf3 n\xf3 kh\xf4ng c\xf3 \u0111\u01a1n v\u1ecb \u0111o\\r\\n\\r\\n3. $\u22121 \\\\le \\\\rho \\\\le 1$ ($\\\\rho = \u22121$ khi va\u0300 chi\u0309 khi $Y = aX + b$ va\u0300  $a \\\\lt 0$ va\u0300 $\\\\rho = 1$ khi v\xe0 ch\u1ec9 khi $Y = aX + b$ va\u0300 $a \\\\gt 0$) \\r\\n\\r\\nCh\u1ee9ng minh t\xednh ch\u1ea5t 3\\r\\n\\r\\n\\r\\n$$\\r\\n0 \\\\le Var(\\\\frac{X}{\\\\sigma_X}\u2212\\\\frac{Y}{\\\\sigma_{Y}}) = Var(\\\\frac{X}{\\\\sigma_X}) + Var(\\\\frac{Y}{\\\\sigma_Y}) \u2212 2Cov(\\\\frac{X}{\\\\sigma_X},\\\\frac{Y}{\\\\sigma_Y}) = 2 \u2212 2\\\\rho \\\\Rightarrow  \\\\rho \\\\le 1 \\r\\n$$\\r\\n\\r\\nT\u01b0\u01a1ng t\u1ef1 $0 \\\\le Var(\\\\frac{X}{\\\\sigma_X}+\\\\frac{Y}{\\\\sigma_{Y}}) \\\\Rightarrow  \\\\rho \\\\ge \u22121$\\r\\n\\r\\n**Bi\u1ec3u di\u1ec5n m\u1ed1i quan h\u1ec7 X, v\xe0 Y v\u1edbi gi\xe1 tr\u1ecb $\\\\rho$ (correlation)**\\r\\n![](https://miro.medium.com/v2/resize:fit:640/format:webp/0*HDrVqgtu3QUN6ltX.png)\\r\\n\\r\\n## So s\xe1nh gi\u1eefa covariance v\xe0 correlation\\r\\n\\r\\n\\r\\n1. C\u1ea3 covariance v\xe0 correlation \u0111\u1ec1u th\u1ec3 hi\u1ec7n m\u1ed1i quan h\u1ec7 gi\u1eefa hai bi\u1ebfn.\\r\\n2. Covariance c\xf3 range t\u1eeb $-\\\\infty$ \u0111\xea\u0301n $+\\\\infty$ . Correlation n\u0103\u0300m trong khoa\u0309ng t\u01b0\u0300 - 1 \u0111\xea\u0301n 1.\\r\\n3. Covariance th\xea\u0309 hi\xea\u0323n m\xf4\u0301i quan h\xea\u0323 gi\u01b0\u0303a hai bi\xea\u0301n, correlation th\xea\u0309 hi\xea\u0323n \u0111\u01b0\u01a1\u0323c m\xf4\u0301i quan h\xea\u0323 gi\u01b0\u0303a hai ho\u0103\u0323c nhi\xea\u0300u bi\xea\u0301n.\\r\\n\\r\\n**Vi\u0301 du\u0323**\\r\\n\\r\\nT\xe2\u0323p d\u01b0\u0303 li\xea\u0323u view cu\u0309a 2 k\xeanh truy\xea\u0300n hi\u0300nh ta\u0323i 1 th\u01a1\u0300i \u0111i\xea\u0309m (20h - 21h th\u01b0\u0301 n\u0103m m\xf4\u0303i tu\xe2\u0300n) trong 1 tha\u0301ng la\u0300\\r\\n\\r\\n$X = [50772, 73756, 74251, 77601]$\\r\\n\\r\\n$Y = [102492, 100406, 97762, 98191]$\\r\\n\\r\\nTa ti\u1ebfn h\xe0nh t\xednh c\xe1c th\xf4ng s\u1ed1 c\u01a1 b\u1ea3n\\r\\n\\r\\n$\\\\mu_X = \\\\frac{50772 + 73756 + 74251 + 77601}{4} = 69095.00$\\r\\n\\r\\n$\\\\mu_Y = \\\\frac{102492 + 100406 + 97762 + 98191}{4} = 99712.75$\\r\\n\\r\\n$\\\\sigma_X^2 = \\\\frac{(50772 - \\\\mu_X)^2 +(73756 - \\\\mu_X)^2 + ... }{4} = 114098405.5 \\\\Rightarrow  \\\\sigma_X = 10681.69$\\r\\n\\r\\n$\\\\sigma_Y^2 = \\\\frac{(102492 - \\\\mu_Y)^2 +(100406 - \\\\mu_Y)^2 + ... }{4} = 114098405.5 \\\\Rightarrow  \\\\sigma_Y = 1892.48$\\r\\n\\r\\nT\u1eeb \u0111\xf3 ta t\xednh covariance v\xe0 correlation\\r\\n\\r\\n$Cov(X,Y) = \\\\frac{(50772 - 69095.00) * (102492- 99712.75) + (73756- 69095.00) * (100406- 99712.75) + ... }{4} = -17673758.0$\\r\\n\\r\\n$Corr(X,Y) = \\\\frac{Cov(X,Y)}{\\\\sigma_X * \\\\sigma_Y} = \\\\frac{-17673758.0} {10681.69 * 1892.48} = -0.87$"}]}')}}]);